import { Component } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../../services/auth.service';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})
export class LoginComponent {
  credentials = { email: '', password: '' };
  errorMessage = '';
  loading = false;

  constructor(private authService: AuthService, private router: Router) {}

  onSubmit() {
    if (!this.credentials.email || !this.credentials.password) {
      return;
    }

    this.loading = true;
    this.errorMessage = '';

    this.authService.login(this.credentials).subscribe({
      next: (response) => {
        this.loading = false;
        if (response.success) {
          this.router.navigate(['/dashboard']);
        } else {
          this.errorMessage = response.message;
        }
      },
      error: (error) => {
        this.loading = false;
        this.errorMessage =
          error.error?.message || 'Login failed. Please try again.';
      }
    });
  }
}
<div class="auth-container">
  <div class="container">
    <div class="row justify-content-center">
      <div class="col-md-6">
        <div class="card auth-card">
          <div class="card-body">
            <h2 class="text-center mb-4">Login to Hostel Management</h2>

            <div *ngIf="errorMessage" class="alert alert-danger">
              {{ errorMessage }}
            </div>

            <form #loginForm="ngForm" (ngSubmit)="onSubmit()" novalidate>
              <div class="mb-3">
                <label class="form-label">Email</label>
                <input
                  type="email"
                  class="form-control"
                  name="email"
                  [(ngModel)]="credentials.email"
                  required
                  pattern="^[a-zA-Z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}$"
                >
                <small class="text-danger"
                  *ngIf="loginForm.submitted && !credentials.email">
                  Email is required
                </small>
              </div>

              <div class="mb-3">
                <label class="form-label">Password</label>
                <input
                  type="password"
                  class="form-control"
                  name="password"
                  [(ngModel)]="credentials.password"
                  required
                  minlength="6"
                >
                <small class="text-danger"
                  *ngIf="loginForm.submitted && credentials.password.length < 6">
                  Password must be at least 6 characters
                </small>
              </div>

              <button
                type="submit"
                class="btn btn-primary w-100"
                [disabled]="loading || !loginForm.valid">
                <span *ngIf="loading">Logging in...</span>
                <span *ngIf="!loading">Login</span>
              </button>
            </form>

            <div class="text-center mt-3">
              <p>Don't have an account?
                <a routerLink="/register">Register here</a>
              </p>
            </div>

          </div>
        </div>
      </div>
    </div>
  </div>
</div>
